#include <stdio.h>
#include <errno.h>
#include <string.h>
typedef struct {
    int code;
    const char *name;
} errno_entry;
int main(void) {
    errno_entry catalog[] = {
        {EPERM,  "EPERM"},
        {ENOENT, "ENOENT"},
        {ESRCH,  "ESRCH"},
        {EINTR,  "EINTR"},
        {EIO,    "EIO"},
        {ENOMEM, "ENOMEM"},
        {EACCES, "EACCES"},
        {EEXIST, "EEXIST"},
        {EINVAL, "EINVAL"},
        {EPIPE,  "EPIPE"}
    };
    int count = sizeof(catalog) / sizeof(catalog[0]);
    printf("=== Errno Catalog (%d entries) ===\n", count);
    for (int i = 0; i < count; i++) {
        printf("%2d %-8s %s\n", catalog[i].code, catalog[i].name, strerror(catalog[i].code));
    }
    return 0;
}

